import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { inlineRefsRule } from "./inline-refs.rule.js";

// a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_inline_refs
describe("inline-refs rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, inlineRefsRule, "@a10n/blueprint-typespec");
  });

  // ─── valid ────────────────────────────────────────────────────────────────

  describe("valid — no inline refs", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_inline_refs
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_01
    it("string with no inline refs passes without diagnostics", async () => {
      await ruleTester
        .expect(`
          @doc("Doing things")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    it("\\\\{@Ref} (double-backslash in source → \\{@Ref} in value) is treated as literal and not resolved", async () => {
      // Use \\{@GhostType} in TypeSpec source: TypeSpec parses \\ → \, so the string
      // value becomes \{@GhostType}. The (?<!\\) lookbehind in the regex skips it.
      // This lets test case prose reference types that only exist in the source being
      // tested, not in the compiled program.
      await ruleTester
        .expect(`
          @doc("Compile a source containing \\\\{@GhostType} and verify the diagnostic.")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });
  });

  describe("valid — fully-qualified name", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_02
    it("resolves a model by its FQN from a different namespace", async () => {
      await ruleTester
        .expect(`
          namespace Outer {
            model Inner {}
          }
          @doc("Produces {@Outer.Inner} records")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_09
    it("resolves an enum by its FQN", async () => {
      await ruleTester
        .expect(`
          namespace Outer {
            enum Status { active, inactive }
          }
          @doc("Checks {@Outer.Status} field")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_10
    it("resolves an operation by its FQN", async () => {
      await ruleTester
        .expect(`
          namespace Outer {
            op doWork(): void;
          }
          @doc("Calls {@Outer.doWork}")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });
  });

  describe("valid — unqualified name resolved via ancestor namespace", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_11
    it("resolves a model declared in the same namespace", async () => {
      await ruleTester
        .expect(`
          @doc("Produces {@ReviewComment} entries")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {
            model ReviewComment { body: string; }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_12
    it("resolves a model declared in a parent namespace", async () => {
      await ruleTester
        .expect(`
          namespace Components {
            model SharedResult {}
          }
          @doc("Returns {@SharedResult}")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });
  });

  describe("valid — scalar, union, interface by name", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_13
    it("resolves a scalar by unqualified name", async () => {
      await ruleTester
        .expect(`
          namespace Components.ReviewAgent {
            scalar Uuid extends string;
            @doc("Identified by a {@Uuid}")
            model Thing {}
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_14
    it("resolves a union by unqualified name", async () => {
      await ruleTester
        .expect(`
          namespace Components.ReviewAgent {
            union Result { ok: string; err: int32; }
            @doc("Returns a {@Result}")
            model Thing {}
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_15
    it("resolves an interface by unqualified name", async () => {
      await ruleTester
        .expect(`
          namespace Components.ReviewAgent {
            interface ReviewOps { fetch(): void; }
            @doc("Implements {@ReviewOps}")
            model Thing {}
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_16
    it("resolves a scalar by FQN", async () => {
      await ruleTester
        .expect(`
          namespace Domain {
            scalar Uuid extends string;
          }
          @doc("Each entity has a {@Domain.Uuid}")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_17
    it("resolves a union by FQN", async () => {
      await ruleTester
        .expect(`
          namespace Domain {
            union Result { ok: string; err: int32; }
          }
          @doc("Returns {@Domain.Result}")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_18
    it("resolves an interface by FQN", async () => {
      await ruleTester
        .expect(`
          namespace Domain {
            interface Ops { fetch(): void; }
          }
          @doc("Implements {@Domain.Ops}")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });
  });

  describe("valid — generic template declaration", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_19
    it("resolves a generic model (template) by unqualified name in @doc", async () => {
      await ruleTester
        .expect(`
          namespace Components.ReviewAgent {
            model Envelope<T> { data: T; }
            @doc("Wraps results in {@Envelope} payloads")
            model Result {}
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_20
    it("resolves a generic model by its FQN", async () => {
      await ruleTester
        .expect(`
          namespace Shared {
            model Page<T> { items: T[]; }
          }
          @doc("Returns {@Shared.Page} of results")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });
  });

  describe("valid — alias type", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_21
    it("resolves an alias type by its unqualified name", async () => {
      await ruleTester
        .expect(`
          namespace Components.ReviewAgent {
            model A { id: string; }
            model B { id: string; }
            alias Entry = A | B;
            @doc("One {@Entry} per request")
            model Thing {}
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_22
    it("resolves an alias type by its FQN", async () => {
      await ruleTester
        .expect(`
          namespace Domain {
            model A { id: string; }
            model B { id: string; }
            alias Entry = A | B;
          }
          @doc("Processes {@Domain.Entry} values")
          @component(#{ type: ComponentType.Agent })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_23
    it("resolves a property shared by all union variants of an alias (e.g. ChecksYamlEntry.id)", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            model SkillCheck { id: string; type: string; }
            model CommandCheck { id: string; run: string; }
            alias ChecksYamlEntry = SkillCheck | CommandCheck;
            @doc("Each {@ChecksYamlEntry.id} must be unique")
            model ChecksYaml { checks: string[]; }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_24
    it("resolves a property shared by all variants of an explicit union declaration (Foo | Bar)", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            model SkillCheck { id: string; type: string; }
            model CommandCheck { id: string; run: string; }
            union ChecksYamlEntry { s: SkillCheck, c: CommandCheck }
            @doc("Each {@ChecksYamlEntry.id} must be unique")
            model ChecksYaml { checks: string[]; }
          }
        `)
        .toBeValid();
    });
  });

  describe("valid — enum member with backtick-escaped dotted name", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_25
    it("resolves a backtick-escaped enum member via dot-joined segments in inline ref", async () => {
      // Member name is \`blueprint.task_context\` (with literal dot).
      // {@CheckInputKind.blueprint.task_context} splits into three dot-segments;
      // the resolver must join remaining segments to find the member.
      await ruleTester
        .expect(`
          namespace Ns {
            enum CheckInputKind { changed_files, \`blueprint.task_context\` }
          }
          @doc("Pass {@Ns.CheckInputKind.blueprint.task_context} for spec-aware skills")
          @component(#{ type: ComponentType.Agent })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_26
    it("resolves unqualified backtick-escaped enum member via dot-joined segments", async () => {
      await ruleTester
        .expect(`
          @doc("Use {@CheckInputKind.blueprint.task_context} for spec-aware skills")
          @component(#{ type: ComponentType.Agent })
          namespace Components.ReviewAgent {
            enum CheckInputKind { changed_files, \`blueprint.task_context\` }
          }
        `)
        .toBeValid();
    });
  });

  describe("valid — enum member (dotted)", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_27
    it("resolves an enum member via FQN", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            enum Color { red, green, blue }
          }
          @doc("Uses {@Ns.Color.red} as default")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_28
    it("resolves an enum member in the same namespace (unqualified type, dotted member)", async () => {
      await ruleTester
        .expect(`
          @doc("Assigns {@Severity.critical} to blocking issues")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {
            enum Severity { critical, major, minor }
          }
        `)
        .toBeValid();
    });
  });

  describe("valid — model property (dotted)", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_29
    it("resolves a model property in the same namespace", async () => {
      await ruleTester
        .expect(`
          @doc("Reads {@Review.status} to check progress")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {
            model Review { status: string; }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_30
    it("resolves a model property via FQN", async () => {
      await ruleTester
        .expect(`
          namespace Domain {
            model User { email: string; }
          }
          @doc("Validates {@Domain.User.email} format")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_31
    it("resolves a model property accessible via using", async () => {
      await ruleTester
        .expect(`
          namespace External {
            model Payload { id: string; }
          }
          using External;
          @doc("Extracts {@Payload.id} from request")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_32
    it("resolves a nested model property (two levels deep)", async () => {
      await ruleTester
        .expect(`
          namespace Components.ReviewAgent {
            model Address { city: string; }
            model User { address: Address; }
            @doc("City via {@User.address.city}")
            model Thing {}
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_33
    it("resolves a model property via ancestor namespace prefix qualification", async () => {
      await ruleTester
        .expect(`
          namespace Components.ReviewAgent {
            model Review { status: string; }
          }
          namespace Components.ReviewAgent.Sub {
            @doc("Reads {@Review.status}")
            model Handler {}
          }
        `)
        .toBeValid();
    });
  });

  describe("valid — using-imported namespace (Strategy A: member qualification)", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_08
    it("resolves unqualified model name brought in by using", async () => {
      await ruleTester
        .expect(`
          namespace External {
            model Widget {}
          }
          using External;
          @doc("Processes {@Widget} items")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_34
    it("resolves unqualified enum name brought in by using", async () => {
      await ruleTester
        .expect(`
          namespace External {
            enum Priority { high, low }
          }
          using External;
          @doc("Applies {@Priority} levels")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });
  });

  describe("valid — using alias expansion (Strategy B: namespace alias)", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_35
    it("resolves a dotted ref where first segment is the using alias", async () => {
      await ruleTester
        .expect(`
          namespace Components.ReviewAgent {
            model ReviewComment {}
          }
          using Components.ReviewAgent;
          @doc("Wraps {@ReviewAgent.ReviewComment} entries")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ApiAgent {}
        `)
        .toBeValid();
    });
  });

  describe("valid — multiple refs in one string", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_36
    it("all refs resolve in a single doc string", async () => {
      await ruleTester
        .expect(`
          @doc("Maps {@Comment} to {@Verdict}")
          @component(#{
            type: ComponentType.Agent,
          })
          namespace Components.ReviewAgent {
            model Comment {}
            model Verdict {}
          }
        `)
        .toBeValid();
    });
  });

  // ─── invalid ──────────────────────────────────────────────────────────────

  describe("invalid — unresolved refs emit diagnostics", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_04
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_inline_refs:Products.A10nBlueprintEngine.Features.SpecReferences.no_std_ref:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_operation_reachability:Products.A10nBlueprintEngine.Features.SpecReferences.no_std_ref:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_inline_refs:Products.A10nBlueprintEngine.Features.SpecReferences.no_generic_ref:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_operation_reachability:Products.A10nBlueprintEngine.Features.SpecReferences.no_generic_ref:must
    it("completely unknown type name in @doc on a model", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            @doc("See {@GhostType} for details")
            model Real {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /GhostType/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_37
    it("unknown type in @doc on a model property", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            model Comment {
              @doc("One of {@MissingEnum} values")
              severity: string;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /MissingEnum/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_38
    it("unknown type in @doc on an operation", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            @doc("Returns {@GhostModel}")
            op fetch(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /GhostModel/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_05
    it("non-existent model property raises diagnostic", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            model Review { status: string; }
            @doc("Reads {@Review.nonExistentField}")
            model Other {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /Review\.nonExistentField/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_39
    it("non-existent enum member raises diagnostic", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            enum Color { red, green }
            @doc("Uses {@Color.purple}")
            model Other {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /Color\.purple/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_40
    it("ref that looks like a dotted path but first segment is not a namespace or type", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            @doc("Check {@NoSuchNs.Whatever}")
            model Real {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /NoSuchNs\.Whatever/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_41
    it("rejects extra segment after an enum member (too deep)", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            enum Color { red, green }
            @doc("Reads {@Color.red.extra}")
            model Other {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /Color\.red\.extra/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_42
    it("rejects a property path through a non-model property type", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            model Review { status: string; }
            @doc("Reads {@Review.status.length}")
            model Other {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /Review\.status\.length/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_06
    it("reports each unresolved ref separately when multiple refs are bad", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            @doc("See {@Ghost1} and {@Ghost2}")
            model Real {}
          }
        `)
        .toEmitDiagnostics([
          { code: "@a10n/blueprint-typespec/inline-refs", message: /Ghost1/ },
          { code: "@a10n/blueprint-typespec/inline-refs", message: /Ghost2/ },
        ]);
    });
  });

  // ─── did-you-mean suggestions ─────────────────────────────────────────────

  describe("invalid — did-you-mean suggestion when close match exists", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_07
    it("suggests the correct enum member when underscore used instead of dot", async () => {
      // {@CheckInputKind.blueprint_task_context} — actual member is `blueprint.task_context`
      await ruleTester
        .expect(`
          namespace Ns {
            enum CheckInputKind { changed_files, \`blueprint.task_context\` }
            @doc("Use {@CheckInputKind.blueprint_task_context} here")
            model Thing {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /did you mean.*blueprint\.task_context|blueprint\.task_context.*did you mean/i,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_43
    it("suggests the correct model name when dots used instead of nothing (LLM hallucination)", async () => {
      // {@My.Model} when actual name is MyModel — normalized form matches
      await ruleTester
        .expect(`
          namespace Ns {
            model MyModel {}
            @doc("Returns {@My.Model} result")
            model Thing {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /did you mean.*MyModel|MyModel.*did you mean/i,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T004.T004_44
    it("no suggestion when ref is completely unrelated", async () => {
      await ruleTester
        .expect(`
          namespace Ns {
            @doc("See {@CompletelyGibberish} for details")
            model Real {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /CompletelyGibberish/,
        });
    });

    it("no suggestion appended when ref is completely unrelated (message has no did-you-mean)", async () => {
      // The framework only supports string/RegExp for message matching, so we assert on
      // the exact default message format which does not contain "Did you mean".
      await ruleTester
        .expect(`
          namespace Ns {
            @doc("See {@CompletelyGibberish} for details")
            model Real {}
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/inline-refs",
          message: /Cannot resolve inline reference \{@CompletelyGibberish\} — no type named "CompletelyGibberish" found in the program\. If this ref describes a hypothetical type in example code/,
        });
    });
  });
});

